mapper.select:
SELECT
FROM lesson l INNER JOIN class_room cr ON cr.id = l.class_id AND cr.is_deleted = 0 INNER JOIN sys_user u ON u.id = l.teacher_id LEFT JOIN course_material m ON m.id = l.material_id AND m.is_deleted = 0 WHERE l.is_deleted = 0 AND l.class_id = #{classId}
AND l.status = #{status}
ORDER BY l.start_time DESC, l.created_at DESC
